using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using YourNamespace.Models;

namespace YourNamespace.Controllers
{
    public class ProductController : Controller
    {
        private readonly YourDbContext _context;

        public ProductController(YourDbContext context)
        {
            _context = context;
        }

        public ActionResult Reviews(int productId)
        {
            var reviews = _context.Reviews
                .Where(r => r.ProductId == productId)
                .OrderByDescending(r => r.CreatedAt);

            return View(reviews);
        }

        [HttpPost]
        public ActionResult AddReview(int productId, string review)
        {
            if (ModelState.IsValid)
            {
                var newReview = new Review
                {
                    ProductId = productId,
                    Content = HttpUtility.HtmlEncode(review),
                    CreatedBy = User.Identity.Name
                };

                _context.Reviews.Add(newReview);
                _context.SaveChanges();

                return RedirectToAction("Reviews", new { id = productId });
            }

            return View("Reviews");
        }
    }
}

public class Review
{
    public int Id { get; set; }
    public int ProductId { get; set; }
    public string Content { get; set; }
    public DateTime CreatedAt { get; set; }
    public string CreatedBy { get; set; }
}